import{_ as t,c as o,o as n,ai as r}from"./chunks/framework.C8-0bFZC.js";const p=JSON.parse('{"title":"MCK Meeting Series","description":"","frontmatter":{"title":"MCK Meeting Series","date":"2025-10-21","banner":"assets/events/20251021_mck_neonephos_series_banner.jpg","bannerMobile":"assets/events/20251021_mck_neonephos_series_banner_mobile.jpg","backgroundhex":"#FFF0B2","tags":["neonephos","mck","ipcei"],"published":true,"sidebar":false,"aside":false,"prev":false,"next":false,"layout":"EventEntryThemeComponent"},"headers":[],"relativePath":"events/2025_10_21_MCK_NeoNephos_Series.md","filePath":"events/2025_10_21_MCK_NeoNephos_Series.md"}'),s={name:"events/2025_10_21_MCK_NeoNephos_Series.md"};function a(i,e,c,d,h,l){return n(),o("div",null,e[0]||(e[0]=[r(`<h1 id="new-neonephos-meeting-series" tabindex="-1">New NeoNephos Meeting Series <a class="header-anchor" href="#new-neonephos-meeting-series" aria-label="Permalink to &quot;New NeoNephos Meeting Series&quot;">​</a></h1><h2 id="the-ipcei-cis-workstream-2-multi-cluster-kubernetes-mck-meeting-series-has-been-opened-up-to-the-neonephos-community-this-event-occurs-on-every-third-tuesday-of-the-month-with-the-first-talk-being-held-on-21st-october-from-10-00-11-30-am-cest-the-event-will-be-recorded" tabindex="-1">The IPCEI-CIS Workstream 2 Multi Cluster Kubernetes (MCK) meeting series has been opened up to the NeoNephos community. This event occurs on every third Tuesday of the month, with the first talk being held on <strong>21st October from 10:00-11:30 am CEST</strong>. The event will be recorded. <a class="header-anchor" href="#the-ipcei-cis-workstream-2-multi-cluster-kubernetes-mck-meeting-series-has-been-opened-up-to-the-neonephos-community-this-event-occurs-on-every-third-tuesday-of-the-month-with-the-first-talk-being-held-on-21st-october-from-10-00-11-30-am-cest-the-event-will-be-recorded" aria-label="Permalink to &quot;The IPCEI-CIS Workstream 2 Multi Cluster Kubernetes (MCK) meeting series has been opened up to the NeoNephos community.
This event occurs on every third Tuesday of the month, with the first talk being held on **21st October from 10:00-11:30 am CEST**.
The event will be recorded.&quot;">​</a></h2><h2 id="agenda" tabindex="-1">Agenda <a class="header-anchor" href="#agenda" aria-label="Permalink to &quot;Agenda&quot;">​</a></h2><p><strong>Headline</strong>: Gardener Autonomous Shoots. Expanding from the Cloud to the Edge.</p><p><strong>Content</strong>: The Apeiro Reference Architecture endorses a common Cloud Operating System (COS) for interoperability across distributed (multi-provider) clouds and edges with the goal to form acontinuum. With COS the new atomic primitive by definition is not the machine but an elastic cluster of machines. In Apeiro, with Gardener, we promote a Managed Kubernetes as a Service (<a href="https://documentation.apeirora.eu/docs/best-practices/multi-cluster-federation/managed-kubernetes-as-a-service" target="_blank" rel="noreferrer">https://documentation.apeirora.eu/docs/best-practices/multi-cluster-federation/managed-kubernetes-as-a-service</a>) for the COS. Gardener leverages the hosted control plane model (Seed/Shoot approach) to provide Kubernetes at massive scale and in a homogeneous way across multiple providers, and our model works exceptionally well for enterprise-grade platforms designed for scalable and elastic cloud environments. Now in Apeiro, we take Gardener to the edge with Autonomous Shoot Clusters! Typically, edge environments pose additional challenges: a) unreliable network connectivity, b) limited automation capabilities, and c) accepted limitations in capacities (single-points-of-failure).</p><p>This session introduces the concept of Autonomous Shoot Clusters and explains how they help to transform Gardener from a cloud-only into a cloud &amp; edge capable platform service.</p><p><strong>Headline</strong>: Introduction to the Sustainability Smart Energy Workload Placement Recommender</p><p><strong>Content</strong>: A short introduction to the concept, architecture and development status of the B7 Sustainability Workstreams AI-Based Smart Energy Workload Placement Recommender.</p><p>👉 Join the meeting <a href="https://teams.microsoft.com/l/meetup-join/19%3ameeting_NjgzOGUxNTItYjBjYy00NWZlLThkMjktNGZhMzM0NTg3MjZl%40thread.v2/0?context=%7b%22Tid%22%3a%2242f7676c-f455-423c-82f6-dc2d99791af7%22%2c%22Oid%22%3a%22f448159f-8442-4772-945c-ad5c1d621625%22%7d" target="_blank" rel="noreferrer">here</a>.</p>`,9)]))}const u=t(s,[["render",a]]);export{p as __pageData,u as default};
